"""
Pytest tests for patient search functionality.
Requirement: A clinician shall search patients by name, MRN, or DOB;
             only patients in their care shall be returned.
"""

import pytest
from datetime import date
from unittest.mock import MagicMock, patch

# ---------------------------------------------------------------------------
# Adjust these imports to match your actual application structure
# ---------------------------------------------------------------------------
from app.services.patient_service import PatientSearchService
from app.models.patient import Patient
from app.models.clinician import Clinician
from app.exceptions import (
    InvalidSearchQueryError,
    UnauthorizedAccessError,
    SearchServiceUnavailableError,
)

# ===========================================================================
# FIXTURES
# ===========================================================================

@pytest.fixture
def clinician_a():
    """Clinician who owns a specific set of patients."""
    return Clinician(id="CLIN-001", name="Dr. Alice Smith", department="Cardiology")


@pytest.fixture
def clinician_b():
    """Clinician with a different, non-overlapping patient panel."""
    return Clinician(id="CLIN-002", name="Dr. Bob Jones", department="Neurology")


@pytest.fixture
def patients_for_clinician_a():
    """Patients assigned to clinician_a."""
    return [
        Patient(
            id="PAT-101",
            mrn="MRN100001",
            first_name="John",
            last_name="Doe",
            dob=date(1980, 6, 15),
            clinician_id="CLIN-001",
        ),
        Patient(
            id="PAT-102",
            mrn="MRN100002",
            first_name="Jane",
            last_name="Doe",
            dob=date(1975, 3, 22),
            clinician_id="CLIN-001",
        ),
        Patient(
            id="PAT-103",
            mrn="MRN100003",
            first_name="Alice",
            last_name="Nguyen",
            dob=date(1990, 11, 8),
            clinician_id="CLIN-001",
        ),
    ]


@pytest.fixture
def patients_for_clinician_b():
    """Patients assigned to clinician_b (should never appear in clinician_a searches)."""
    return [
        Patient(
            id="PAT-201",
            mrn="MRN200001",
            first_name="Robert",
            last_name="Brown",
            dob=date(1965, 7, 30),
            clinician_id="CLIN-002",
        ),
        Patient(
            id="PAT-202",
            mrn="MRN200002",
            first_name="Jane",          # Same first name as PAT-102
            last_name="Brown",
            dob=date(1975, 3, 22),      # Same DOB as PAT-102
            clinician_id="CLIN-002",
        ),
    ]


@pytest.fixture
def patient_repository(patients_for_clinician_a, patients_for_clinician_b):
    """
    Mock repository that simulates the data store.
    Returns only patients whose clinician_id matches the requesting clinician.
    """
    all_patients = patients_for_clinician_a + patients_for_clinician_b

    repo = MagicMock()

    def _search(clinician_id, **kwargs):
        panel = [p for p in all_patients if p.clinician_id == clinician_id]
        results = panel

        if "name" in kwargs:
            term = kwargs["name"].lower()
            results = [
                p for p in results
                if term in p.first_name.lower() or term in p.last_name.lower()
            ]
        if "mrn" in kwargs:
            results = [p for p in results if p.mrn == kwargs["mrn"]]
        if "dob" in kwargs:
            results = [p for p in results if p.dob == kwargs["dob"]]

        return results

    repo.search.side_effect = _search
    return repo


@pytest.fixture
def search_service(patient_repository):
    """PatientSearchService wired with the mock repository."""
    return PatientSearchService(repository=patient_repository)


# ===========================================================================
# HELPER
# ===========================================================================

def assert_all_patients_belong_to_clinician(patients, clinician):
    """Utility assertion: every returned patient must belong to the clinician."""
    for patient in patients:
        assert patient.clinician_id == clinician.id, (
            f"Patient {patient.id} (clinician_id={patient.clinician_id}) "
            f"does not belong to clinician {clinician.id}"
        )


# ===========================================================================
# 1. SEARCH BY NAME
# ===========================================================================

class TestSearchByName:

    def test_search_by_exact_last_name_returns_matching_patients(
        self, search_service, clinician_a
    ):
        results = search_service.search(clinician=clinician_a, name="Doe")
        assert len(results) == 2
        mrns = {p.mrn for p in results}
        assert "MRN100001" in mrns
        assert "MRN100002" in mrns

    def test_search_by_exact_first_name_returns_matching_patient(
        self, search_service, clinician_a
    ):
        results = search_service.search(clinician=clinician_a, name="Alice")
        assert len(results) == 1
        assert results[0].mrn == "MRN100003"

    def test_search_by_partial_name_returns_matching_patients(
        self, search_service, clinician_a
    ):
        results = search_service.search(clinician=clinician_a, name="doe")
        assert len(results) == 2

    def test_search_by_name_is_case_insensitive(
        self, search_service, clinician_a
    ):
        results_upper = search_service.search(clinician=clinician_a, name="DOE")
        results_lower = search_service.search(clinician=clinician_a, name="doe")
        assert {p.id for p in results_upper} == {p.id for p in results_lower}

    def test_search_by_name_with_no_match_returns_empty_list(
        self, search_service, clinician_a
    ):
        results = search_service.search(clinician=clinician_a, name="Zzyzx")
        assert results == []

    def test_search_by_name_returns_only_clinicians_own_patients(
        self, search_service, clinician_a
    ):
        # "Jane" exists in both clinician_a and clinician_b panels
        results = search_service.search(clinician=clinician_a, name="Jane")
        assert_all_patients_belong_to_clinician(results, clinician_a)
        assert all(r.clinician_id == "CLIN-001" for r in results)

    def test_search_by_name_does_not_return_other_clinicians_patients(
        self, search_service, clinician_a, patients_for_clinician_b
    ):
        other_ids = {p.id for p in patients_for_clinician_b}
        results = search_service.search(clinician=clinician_a, name="Jane")
        returned_ids = {p.id for p in results}
        assert returned_ids.isdisjoint(other_ids)

    def test_search_by_name_empty_string_raises_error(
        self, search_service, clinician_a
    ):
        with pytest.raises(InvalidSearchQueryError):
            search_service.search(clinician=clinician_a, name="")

    def test_search_by_name_whitespace_only_raises_error(
        self, search_service, clinician_a
    ):
        with pytest.raises(InvalidSearchQueryError):
            search_service.search(clinician=clinician_a, name="   ")


# ===========================================================================
# 2. SEARCH BY MRN
# ===========================================================================

class TestSearchByMRN:

    def test_search_by_exact_mrn_returns_correct_patient(
        self, search_service, clinician_a
    ):
        results = search_service.search(clinician=clinician_a, mrn="MRN100001")
        assert len(results) == 1
        assert results[0].id == "PAT-101"

    def test_search_by_mrn_returns_only_one_patient(
        self, search_service, clinician_a
    ):
        """MRN is unique; result set must never exceed one record."""
        results = search_service.search(clinician=clinician_a, mrn="MRN100002")
        assert len(results) <= 1

    def test_search_by_mrn_not_in_panel_returns_empty_list(
        self, search_service, clinician_a
    ):
        """MRN exists in the system but belongs to another clinician's patient."""
        results = search_service.search(clinician=clinician_a, mrn="MRN200001")
        assert results == []

    def test_search_by_mrn_unknown_mrn_returns_empty_list(
        self, search_service, clinician_a
    ):
        results = search_service.search(clinician=clinician_a, mrn="MRN999999")
        assert results == []

    def test_search_by_mrn_returns_only_clinicians_own_patients(
        self, search_service, clinician_a
    ):
        results = search_service.search(clinician=clinician_a, mrn="MRN100003")
        assert_all_patients_belong_to_clinician(results, clinician_a)

    def test_search_by_mrn_invalid_format_raises_error(
        self, search_service, clinician_a
    ):
        with pytest.raises(InvalidSearchQueryError):
            search_service.search(clinician=clinician_a, mrn="!!!INVALID!!!")

    def test_search_by_mrn_empty_string_raises_error(
        self, search_service, clinician_a
    ):
        with pytest.raises(InvalidSearchQueryError):
            search_service.search(clinician=clinician_a, mrn="")


# ===========================================================================
# 3. SEARCH BY DATE OF BIRTH
# ===========================================================================

class TestSearchByDOB:

    def test_search_by_exact_dob_returns_matching_patient(
        self, search_service, clinician_a
    ):
        results = search_service.search(
            clinician=clinician_a, dob=date(1980, 6, 15)
        )
        assert len(results) == 1
        assert results[0].mrn == "MRN100001"

    def test_search_by_dob_with_no_match_returns_empty_list(
        self, search_service, clinician_a
    ):
        results = search_service.search(
            clinician=clinician_a, dob=date(2000, 1, 1)
        )
        assert results == []

    def test_search_by_dob_returns_only_clinicians_own_patients(
        self, search_service, clinician_a
    ):
        """
        DOB 1975-03-22 is shared between PAT-102 (clinician_a) and
        PAT-202 (clinician_b); only PAT-102 must be returned.
        """
        results = search_service.search(
            clinician=clinician_a, dob=date(1975, 3, 22)
        )
        assert_all_patients_belong_to_clinician(results, clinician_a)
        assert all(r.clinician_id == "CLIN-001" for r in results)

    def test_search_by_dob_does_not_return_other_clinicians_patients(
        self, search_service, clinician_a, patients_for_clinician_b
    ):
        other_ids = {p.id for p in patients_for_clinician_b}
        results = search_service.search(
            clinician=clinician_a, dob=date(1975, 3, 22)
        )
        returned_ids = {p.id for p in results}
        assert returned_ids.isdisjoint(other_ids)

    def test_search_by_dob_future_date_raises_error(
        self, search_service, clinician_a
    ):
        future_date = date(2099, 12, 31)
        with pytest.raises(InvalidSearchQueryError):
            search_service.search(clinician=clinician_a, dob=future_date)

    def test_search_by_dob_accepts_date_object(
        self, search_service, clinician_a
    ):
        """Service must accept a Python date object without raising TypeError."""
        results = search_service.search(
            clinician=clinician_a, dob=date(1990, 11, 8)
        )
        assert isinstance(results, list)

    def test_search_by_dob_string_format_iso(
        self, search_service, clinician_a
    ):
        """Service must handle ISO-formatted string '1980-06-15'."""
        results = search_service.search(
            clinician=clinician_a, dob="1980-06-15"
        )
        assert len(results) == 1
        assert results[0].mrn == "MRN100001"

    def test_search_by_dob_invalid_string_raises_error(
        self, search_service, clinician_a
    ):
        with pytest.raises(InvalidSearchQueryError):
            search_service.search(clinician=clinician_a, dob="not-a-date")


# ===========================================================================
# 4. COMBINED SEARCH CRITERIA
# ===========================================================================

class TestCombinedSearchCriteria:

    def test_name_and_dob_narrows_results(
        self, search_service, clinician_a
    ):
        results = search_service.search(
            clinician=clinician_a, name="Doe", dob=date(1980, 6, 15)
        )
        assert len(results) == 1
        assert results[0].mrn == "MRN100001"

    def test_name_and_mrn_returns_single_patient(
        self, search_service, clinician_a
    ):
        results = search_service.search(
            clinician=clinician_a, name="John", mrn="MRN100001"
        )
        assert len(results) == 1
        assert results[0].id == "PAT-101"

    def test_conflicting_criteria_returns_empty_list(
        self, search_service, clinician_a
    ):
        """Name matches one patient but MRN belongs to a different patient."""
        results = search_service.search(
            clinician=clinician_a, name="Alice", mrn="MRN100001"
        )
        assert results == []

    def test_no_search_criteria_raises_error(
        self, search_service, clinician_a
    ):
        with pytest.raises(InvalidSearchQueryError):
            search_service.search(clinician=clinician_a)


# ===========================================================================
# 5. AUTHORIZATION / CARE RELATIONSHIP ENFORCEMENT
# ===========================================================================

class TestAuthorizationEnforcement:

    def test_clinician_b_cannot_see_clinician_a_patients_by_name(
        self, search_service, clinician_b
    ):
        results = search_service.search(clinician=clinician_b, name="Doe")
        assert results == []

    def test_clinician_b_cannot_retrieve_clinician_a_patient_by_mrn(
        self, search_service, clinician_b
    ):
        results = search_service.search(clinician=clinician_b, mrn="MRN100001")
        assert results == []

    def test_clinician_b_cannot_retrieve_clinician_a_patient_by_dob(
        self, search_service, clinician_b
    ):
        results = search_service.search(
            clinician=clinician_b, dob=date(1980, 6, 15)
        )
        assert results == []

    def test_unauthenticated_clinician_raises_unauthorized_error(
        self, search_service
    ):
        with pytest.raises(UnauthorizedAccessError):
            search_service.search(clinician=None, name="Doe")

    def test_inactive_clinician_raises_unauthorized_error(
        self, search_service
    ):
        inactive_clinician = Clinician(
            id="CLIN-999", name="Dr. Inactive", department="None", is_active=False
        )
        with pytest.raises(UnauthorizedAccessError):
            search_service.search(clinician=inactive_clinician, name="Doe")

    def test_results_never_contain_patients_outside_care_panel(
        self, search_service, clinician_a, patients_for_clinician_b
    ):
        """
        Broad search: ensure no cross-contamination regardless of query.
        Runs multiple searches and verifies care-relationship invariant.
        """
        other_ids = {p.id for p in patients_for_clinician_b}
        queries = [
            {"name": "Jane"},
            {"dob": date(1975, 3, 22)},
            {"name": "Brown"},
        ]
        for query in queries:
            results = search_service.search(clinician=clinician_a, **query)
            returned_ids = {p.id for p in results}
            assert returned_ids.isdisjoint(other_ids), (
                f"Query {query} returned patient(s) outside clinician_a's panel: "
                f"{returned_ids & other_ids}"
            )


# ===========================================================================
# 6. RESULT CONTENT AND STRUCTURE
# ===========================================================================

class TestResultStructure:

    def test_returned_patient_has_required_fields(
        self, search_service, clinician_a
    ):
        results = search_service.search(clinician=clinician_a, name="John")
        assert len(results) >= 1
        patient = results[0]
        assert hasattr(patient, "id")
        assert hasattr(patient, "mrn")
        assert hasattr(patient, "first_name")
        assert hasattr(patient, "last_name")
        assert hasattr(patient, "dob")

    def test_search_returns_list_type(
        self, search_service, clinician_a
    ):
        results = search_service.search(clinician=clinician_a, name="Doe")
        assert isinstance(results, list)

    def test_empty_panel_returns_empty_list(
        self, search_service
    ):
        empty_panel_clinician = Clinician(
            id="CLIN-100", name="Dr. No Patients", department="Admin"
        )
        results = search_service.search(
            clinician=empty_panel_clinician, name="Doe"
        )
        assert results == []


# ===========================================================================
# 7. EDGE CASES
# ===========================================================================

class TestEdgeCases:

    def test_name_with_special_characters_raises_or_returns_empty(
        self, search_service, clinician_a
    ):
        """SQL injection / special chars must not cause unhandled exceptions."""
        try:
            results = search_service.search(
                clinician=clinician_a, name="'; DROP TABLE patients;--"
            )
            assert results == []
        except InvalidSearchQueryError:
            pass  # Also acceptable

    def test_very_long_name_string_raises_error(
        self, search_service, clinician_a
    ):
        with pytest.raises(InvalidSearchQueryError):
            search_service.search(clinician=clinician_a, name="A" * 300)

    def test_search_result_count_does_not_exceed_panel_size(
        self, search_service, clinician_a, patients_for_clinician_a
    ):
        results = search_service.search(clinician=clinician_a, name="")
        # Empty name raises; this test ensures prior tests don't leak state.
        # Reframe: search by common letter
        try:
            results = search_service.search(clinician=clinician_a, name="a")
            assert len(results) <= len(patients_for_clinician_a)
        except InvalidSearchQueryError:
            pytest.skip("Single-character search not supported by this implementation.")

    @patch("app.services.patient_service.PatientSearchService._call_repository")
    def test_service_unavailable_raises_appropriate_error(
        self, mock_repo_call, search_service, clinician_a
    ):
        mock_repo_call.side_effect = Exception("DB connection lost")
        with pytest.raises(SearchServiceUnavailableError):
            search_service.search(clinician=clinician_a, name="Doe")

    def test_duplicate_results_are_not_returned(
        self, search_service, clinician_a
    ):
        """Each patient record must appear at most once in a result set."""
        results = search_service.search(clinician=clinician_a, name="Doe")
        ids = [p.id for p in results]
        assert len(ids) == len(set(ids))
